%[text] # 例7.6（変換符号化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example07_06"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";

close all

%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1) %[output:229319d8]
subplot(1,3,1) %[output:229319d8]
imshow(X) %[output:229319d8]
title('原画像') %[output:229319d8]
%imwrite(X,fullfile(resfolder,myfilename+"org"),imgfmt)

% GPUに転送
%X = gpuArray(X);
%%
%[text] ## 平均ビット数
alpha = 4;
%%
%[text] ## $8\\times 8$ブロックDCT
% DCT行列
C = dctmtx(8) %[output:1dc5b0e9]

sz = size(X);

% 二次元DCT
Ydct = blockproc(X,[8 8],@(x) C*x.data*C.');
% 最適ビット割り当て
[Qtable,alphap] = fcn_bitalloc(Ydct,[8 8],alpha) %[output:3c872318] %[output:0a57efdc]
% 最小最大正規化
[Udct,Ymin,Ymax] = fcn_minmaxnorm(Ydct,[8 8]);
% 量子化
Uhat = round(Udct./Qtable);
% 逆量子化
Vhat = Qtable.*Uhat;
% 最小最大逆正規化
Yhat = fcn_minmaxdenorm(Vhat,sz,Ymin,Ymax);
% 二次元逆DCT
Xdct = blockproc(Yhat,[8 8],@(x) C.'*x.data*C);

subplot(1,3,2) %[output:35ae0b2e]
imshow(Xdct) %[output:35ae0b2e]
title("DCT " + num2str(alpha)+" bpp PSNR: " + num2str(psnr(X,Xdct)) + " dB") %[output:35ae0b2e]
imwrite(Xdct,fullfile(resfolder,"fig07-10a.png"))
%%
%[text] ## $8\\times 8$ブロックDHT
% DHT行列
J = log2(8);
H = dhtmtx(J) %[output:668996d5]

sz = size(X);

% 二次元DCT
Ydht = blockproc(X,[8 8],@(x) H*x.data*H.');
% 最適ビット割り当て
[Qtable,alphap] = fcn_bitalloc(Ydht,[8 8],alpha) %[output:6529999e] %[output:6a463b7f]
% 最小最大正規化
[Udht,Ymin,Ymax] = fcn_minmaxnorm(Ydht,[8 8]) %[output:114a71eb] %[output:3e506d8f] %[output:6d61d7fa]
% 量子化
Uhat = round(Udht./Qtable);
% 逆量子化
Vhat = Qtable.*Uhat;
% 最小最大逆正規化
Yhat = fcn_minmaxdenorm(Vhat,sz,Ymin,Ymax);
% 二次元逆DCT
Xdht = blockproc(Yhat,[8 8],@(x) H.'*x.data*H);

subplot(1,3,3) %[output:2082a4b5]
imshow(Xdht) %[output:2082a4b5]
title("DHT " + num2str(alpha)+" bpp PSNR: " + num2str(psnr(X,Xdht)) + " dB") %[output:2082a4b5]
imwrite(Xdht,fullfile(resfolder,"fig07-10b.png"))
%%
%[text] ## DHT行列
function H = dhtmtx(J)
H = 1;
I = 1;
for j=1:J
    M = 2^j;
    H = 1/sqrt(2)*[kron(H,[1 1]); kron(I,[1 -1])];
    I = eye(M);
end
end
%[text] ## 最小最大正規化とその逆写像
function [Yb,Xmin,Xmax] = fcn_minmaxnorm(X,mn)
% ブロックリシェイプ
Xb = fcn_blockreshape(X,mn);

% 係数ごとの最小値と最大値
Xmin = min(Xb,[],3);
Xmax = max(Xb,[],3);

% 最小最大正規化
Yb = (Xb-Xmin)./(Xmax-Xmin);

end

function X = fcn_minmaxdenorm(Yb,sz,Xmin,Xmax)

% 最小最大正規化
Xb = Yb.*(Xmax-Xmin) + Xmin;

% ブロックデシェイプ
X = fcn_blockdeshape(Xb,sz);

end
%[text] ## 最適ビット割り当て関数
function [Qtable,alphap] = fcn_bitalloc(Y,mn,alpha)
% ブロックリシェイプ
Yb = fcn_blockreshape(Y,mn);              % mb x nb x numBlocks

% 係数ごとの分散
varyb = var(Yb,0,3);

% ビット割り当て
M = prod(mn);
alphap = alpha + (1/2)*log2(varyb/(prod(varyb,"all")^(1/M)));

% 量子化テーブル
Qtable = 1./(2.^alphap-1);

end
%[text] ## ブロックリシェイプ
function Y = fcn_blockreshape(X,mn)
% 入力 Y をブロックサイズ mn のブロック列として扱うためのリシェイプ処理
% 出力は mn(1) x mn(2) x numBlocks の3次元配列
% ただし Y は画像と同じサイズの2次元配列を想定
[m,n] = size(X);
mb = mn(1); nb = mn(2);
if mod(m,mb)~=0 || mod(n,nb)~=0
    error('Image size must be divisible by block size mn.');
end
nBlocksRow = m/mb;
nBlocksCol = n/nb;
numBlocks = nBlocksRow * nBlocksCol;

% 列ごとにブロック化するためにまずブロック行方向に reshape -> permute -> reshape
% 手順： (mb x nBlocksRow) x (nb x nBlocksCol) をブロック毎に抽出
X_reshaped = reshape(X, mb, nBlocksRow, nb, nBlocksCol);   % mb x nBlocksRow x nb x nBlocksCol
X_perm = permute(X_reshaped, [1 3 2 4]);                    % mb x nb x nBlocksRow x nBlocksCol
Y = reshape(X_perm, mb, nb, numBlocks);               % mb x nb x numBlocks
end
%[text] ## ブロックデシェイプ
function Y = fcn_blockdeshape(X,sz)
% ブロックリシェイプの逆写像
% X: mb x nb x numBlocks のブロック列
% sz: 元画像のサイズ [m n]
% Y: 元画像サイズの 2D 配列 (m x n)

% 入力チェック
[mb, nb, numBlocks] = size(X);
if numel(sz)~=2
    error('sz must be a two-element vector [m n].');
end
m = sz(1); n = sz(2);

if mod(m,mb)~=0 || mod(n,nb)~=0
    error('Image size must be divisible by block size inferred from X.');
end

nBlocksRow = m/mb;
nBlocksCol = n/nb;
if numBlocks ~= nBlocksRow * nBlocksCol
    error('Number of blocks does not match provided image size.');
end

% 逆変換手順:
% X (mb x nb x nBlocks) -> X_perm (mb x nb x nBlocksRow x nBlocksCol)
X_perm = reshape(X, mb, nb, nBlocksRow, nBlocksCol);
% permute back to (mb x nBlocksRow x nb x nBlocksCol)
X_reshaped = permute(X_perm, [1 3 2 4]);
% 最後に reshape to (m x n)
Y = reshape(X_reshaped, m, n);
end
